module shift_register(clk, load, in, shift, out);
    input clk, load, shift;
    input [3:0] in;
    output [3:0] out;
    reg [3:0] invalid_reg;

    always @(posedge clk) begin
        if (load) begin
            invalid_reg <= in;
        end else if (shift) begin
            invalid_reg <= {invalid_reg[2:0], 1'b0};
        end
    end

    assign out = invalid_reg;
endmodule
